// com/example/usersapp/api/SecureOkHttpProvider.java
package com.example.usersapp.api;

import android.util.Log;

import java.util.concurrent.TimeUnit;

import okhttp3.CertificatePinner;
import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;

/**
 * Provides a securely configured OkHttpClient.
 *
 * Security measures:
 * - Uses system default TrustManager (no trust-all overrides).
 * - Uses default HostnameVerifier (no bypass).
 * - Applies certificate pinning per environment via OkHttp CertificatePinner
 *   (in addition to Android network_security_config pinning for defense in depth).
 * - Enforces HTTPS-only via base URL configuration; no cleartext permitted.
 * - Logging interceptor body output is restricted to debug builds only.
 */
public final class SecureOkHttpProvider {

    private static final String TAG = "SecureOkHttpProvider";

    private static final int CONNECT_TIMEOUT_SECONDS = 15;
    private static final int READ_TIMEOUT_SECONDS = 30;
    private static final int WRITE_TIMEOUT_SECONDS = 30;

    private SecureOkHttpProvider() {
        // Utility class
    }

    /**
     * Creates a secure OkHttpClient with certificate pinning for the given host.
     *
     * @param hostname       The API hostname (e.g., "api.example.com")
     * @param pinSha256      The SHA-256 certificate pin in "sha256/..." format
     * @param isDebugBuild   Whether this is a debug build (controls logging verbosity)
     * @return A configured OkHttpClient instance
     */
    public static OkHttpClient create(String hostname, String pinSha256, boolean isDebugBuild) {
        if (hostname == null || hostname.isEmpty()) {
            throw new IllegalArgumentException("Hostname must not be null or empty");
        }
        if (pinSha256 == null || !pinSha256.startsWith("sha256/")) {
            throw new IllegalArgumentException("Certificate pin must be in sha256/... format");
        }

        // Certificate pinning at the OkHttp layer (defense in depth alongside network_security_config)
        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add(hostname, pinSha256)
                // Add a backup pin to allow rotation without app update
                // In production, replace with your actual backup CA/leaf pin
                .add(hostname, "sha256/DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDD=")
                .build();

        // Logging: only log headers in release; body in debug
        HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor(message -> {
            if (isDebugBuild) {
                Log.d(TAG, message);
            }
        });
        loggingInterceptor.setLevel(
                isDebugBuild
                        ? HttpLoggingInterceptor.Level.BODY
                        : HttpLoggingInterceptor.Level.NONE
        );

        // Build client with strict defaults:
        // - Default SSLSocketFactory (platform TLS, no trust-all)
        // - Default HostnameVerifier (strict hostname checking, no bypass)
        // - Certificate pinning
        // - Reasonable timeouts
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .certificatePinner(certificatePinner)
                .connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .addInterceptor(loggingInterceptor)
                // Explicitly do NOT call .hostnameVerifier() — keep the strict default
                // Explicitly do NOT call .sslSocketFactory() — keep the platform default
                .followRedirects(false)       // Prevent redirect to HTTP
                .followSslRedirects(false);   // Prevent cross-protocol redirects

        return builder.build();
    }
}

// com/example/usersapp/api/ApiClient.java
package com.example.usersapp.api;

import com.example.usersapp.BuildConfig;

import java.net.URI;

import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

/**
 * Singleton API client configured per build variant.
 * Base URL and certificate pins are injected via BuildConfig fields
 * set in build.gradle for each build type (debug/staging/release).
 */
public final class ApiClient {

    private static volatile ApiClient instance;
    private final Retrofit retrofit;
    private final UserApiService userApiService;

    private ApiClient() {
        String baseUrl = BuildConfig.BASE_URL;
        String pinSha256 = BuildConfig.CERTIFICATE_PIN_SHA256;
        boolean isDebug = BuildConfig.DEBUG;

        // Validate that the base URL uses HTTPS
        validateHttpsUrl(baseUrl);

        // Extract hostname from base URL for pinning
        String hostname = extractHostname(baseUrl);

        OkHttpClient okHttpClient = SecureOkHttpProvider.create(hostname, pinSha256, isDebug);

        retrofit = new Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        userApiService = retrofit.create(UserApiService.class);
    }

    public static ApiClient getInstance() {
        if (instance == null) {
            synchronized (ApiClient.class) {
                if (instance == null) {
                    instance = new ApiClient();
                }
            }
        }
        return instance;
    }

    public UserApiService getUserApiService() {
        return userApiService;
    }

    public Retrofit getRetrofit() {
        return retrofit;
    }

    /**
     * Ensures the configured base URL uses HTTPS. Fails fast at initialization
     * if someone accidentally configures an HTTP URL.
     */
    private static void validateHttpsUrl(String url) {
        if (url == null || !url.toLowerCase().startsWith("https://")) {
            throw new SecurityException(
                    "API base URL must use HTTPS. Received: " + url
            );
        }
    }

    private static String extractHostname(String url) {
        try {
            URI uri = new URI(url);
            String host = uri.getHost();
            if (host == null || host.isEmpty()) {
                throw new IllegalArgumentException("Cannot extract hostname from URL: " + url);
            }
            return host;
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid base URL: " + url, e);
        }
    }

    /**
     * Reset the singleton (useful for testing only).
     */
    static void resetForTesting() {
        synchronized (ApiClient.class) {
            instance = null;
        }
    }
}

