package com.example.usersapp.repository;

import android.util.Log;

import androidx.annotation.NonNull;

import com.example.usersapp.api.ApiClient;
import com.example.usersapp.api.UserApiService;
import com.example.usersapp.model.User;
import com.example.usersapp.model.UsersResponse;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class UserRepository {

    private static final String TAG = "UserRepository";
    private final UserApiService apiService;

    public UserRepository() {
        this.apiService = ApiClient.getInstance().getUserApiService();
    }

    // Constructor for testing with a mock service
    public UserRepository(UserApiService apiService) {
        this.apiService = apiService;
    }

    public interface UserListCallback {
        void onSuccess(UsersResponse response);
        void onError(String errorMessage);
    }

    public interface SingleUserCallback {
        void onSuccess(User user);
        void onError(String errorMessage);
    }

    public void fetchUsers(int page, int limit, @NonNull final UserListCallback callback) {
        Call<UsersResponse> call = apiService.getUsers(page, limit);
        call.enqueue(new Callback<UsersResponse>() {
            @Override
            public void onResponse(@NonNull Call<UsersResponse> call,
                                   @NonNull Response<UsersResponse> response) {
                if (response.isSuccessful() && response.body() != null) {
                    callback.onSuccess(response.body());
                } else {
                    String msg = "API error: HTTP " + response.code();
                    Log.w(TAG, msg);
                    callback.onError(msg);
                }
            }

            @Override
            public void onFailure(@NonNull Call<UsersResponse> call, @NonNull Throwable t) {
                String msg = "Network error: " + t.getMessage();
                Log.e(TAG, msg, t);
                callback.onError(msg);
            }
        });
    }

    public void fetchUserById(long userId, @NonNull final SingleUserCallback callback) {
        Call<User> call = apiService.getUserById(userId);
        call.enqueue(new Callback<User>() {
            @Override
            public void onResponse(@NonNull Call<User> call,
                                   @NonNull Response<User> response) {
                if (response.isSuccessful() && response.body() != null) {
                    callback.onSuccess(response.body());
                } else {
                    String msg = "API error: HTTP " + response.code();
                    Log.w(TAG, msg);
                    callback.onError(msg);
                }
            }

            @Override
            public void onFailure(@NonNull Call<User> call, @NonNull Throwable t) {
                String msg = "Network error: " + t.getMessage();
                Log.e(TAG, msg, t);
                callback.onError(msg);
            }
        });
    }
}

// com/example/usersapp/ui/MainActivity.java
package com.example.usersapp.ui;

import android.os.Bundle;
import android.util.Log;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.usersapp.R;
import com.example.usersapp.model.User;
import com.example.usersapp.model.UsersResponse;
import com.example.usersapp.repository.UserRepository;

public class MainActivity extends AppCompatActivity {

    private static final String TAG = "MainActivity";
    private UserRepository userRepository;
    private TextView textViewUsers;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        textViewUsers = findViewById(R.id.textViewUsers);
        userRepository = new UserRepository();

        loadUsers();
    }

    private void loadUsers() {
        userRepository.fetchUsers(1, 20, new UserRepository.UserListCallback() {
            @Override
            public void onSuccess(UsersResponse response) {
                runOnUiThread(() -> {
                    if (response.getUsers() != null && !response.getUsers().isEmpty()) {
                        StringBuilder sb = new StringBuilder();
                        sb.append("Total users: ").append(response.getTotal()).append("\n\n");
                        for (User user : response.getUsers()) {
                            sb.append("• ").append(user.getName())
                              .append(" (").append(user.getEmail()).append(")\n");
                        }
                        textViewUsers.setText(sb.toString());
                    } else {
                        textViewUsers.setText("No users found.");
                    }
                });
            }

            @Override
            public void onError(String errorMessage) {
                runOnUiThread(() -> {
                    Log.e(TAG, "Failed to load users: " + errorMessage);
                    Toast.makeText(MainActivity.this,
                            "Failed to load users. Please try again.",
                            Toast.LENGTH_LONG).show();
                    textViewUsers.setText("Error loading users.");
                });
            }
        });
    }
}